<?php
namespace App\Controllers;
use App\Core\Auth; use App\Core\Database; use App\Core\View;
final class ReportController
{
 public function index():void{Auth::requireLogin();$pdo=Database::connection();$from=$_GET['from']??date('Y-m-01');$to=$_GET['to']??date('Y-m-t');$rev=$pdo->prepare("SELECT DATE(issue_date) day,SUM(total) total FROM invoices WHERE issue_date BETWEEN ? AND ? AND status<>'void' GROUP BY DATE(issue_date) ORDER BY day");$rev->execute([$from,$to]);$svc=$pdo->prepare("SELECT COALESCE(j.service_summary,'Other') service,COUNT(*) jobs,SUM(i.total) revenue FROM jobs j LEFT JOIN invoices i ON i.job_id=j.id WHERE DATE(COALESCE(j.scheduled_start,j.created_at)) BETWEEN ? AND ? GROUP BY service ORDER BY revenue DESC");$svc->execute([$from,$to]);$summary=$pdo->prepare("SELECT COUNT(*) invoices,COALESCE(SUM(total),0) revenue,COALESCE(SUM(balance_due),0) outstanding FROM invoices WHERE issue_date BETWEEN ? AND ? AND status<>'void'");$summary->execute([$from,$to]);$profit=$pdo->prepare("SELECT COALESCE(u.name,'Unassigned') crew,COALESCE(v.unit_number,'No vehicle') vehicle,COUNT(DISTINCT j.id) jobs,COALESCE(SUM(i.total),0) revenue,COALESCE(SUM((TIMESTAMPDIFF(MINUTE,t.clock_in,t.clock_out)-t.break_minutes)/60*t.hourly_cost),0) labor_cost,COALESCE(SUM(ju.quantity*ju.unit_cost),0) material_cost FROM jobs j LEFT JOIN users u ON u.id=j.assigned_user_id LEFT JOIN vehicles v ON v.id=j.assigned_vehicle_id LEFT JOIN invoices i ON i.job_id=j.id AND i.status<>'void' LEFT JOIN time_entries t ON t.job_id=j.id AND t.clock_out IS NOT NULL LEFT JOIN job_inventory_usage ju ON ju.job_id=j.id WHERE DATE(COALESCE(j.scheduled_start,j.created_at)) BETWEEN ? AND ? GROUP BY u.id,v.id ORDER BY revenue DESC");$profit->execute([$from,$to]);View::render('portal/reports/index',['title'=>'Reports','from'=>$from,'to'=>$to,'revenue'=>$rev->fetchAll(),'services'=>$svc->fetchAll(),'summary'=>$summary->fetch(),'profitability'=>$profit->fetchAll()],'portal');}
}
